const item = $input.first();

// === UZUPELNIJ SWOJ KLUCZ API ===
const GEMINI_API_KEY = 'YOUR_GEMINI_API_KEY';
// ==================================

const baseImageUrl = item.json.base_image_url;
const labelImageUrl = item.json.label_image_url;
const lidImageUrl = item.json.lid_image_url;
const productName = item.json.product_name;
const airtableId = item.json.id;

async function urlToBase64(url) {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Nie udalo sie pobrac obrazu: ${url} (status: ${response.status})`);
  }
  const arrayBuffer = await response.arrayBuffer();
  return Buffer.from(arrayBuffer).toString('base64');
}

function getMimeType(url) {
  const lower = url.toLowerCase().split('?')[0];
  if (lower.endsWith('.png')) return 'image/png';
  if (lower.endsWith('.webp')) return 'image/webp';
  return 'image/jpeg';
}

const [baseB64, labelB64, lidB64] = await Promise.all([
  urlToBase64(baseImageUrl),
  urlToBase64(labelImageUrl),
  urlToBase64(lidImageUrl),
]);

const prompt = `ULTRA PHOTOREALISTIC PRODUCT IMAGE EDIT.

Use the attached base image of the premium gift box as the main source image.
Preserve the full original composition EXACTLY.

EDIT ONLY THESE TWO PRINTED AREAS:
1. Replace the front candle label on the jar on the left with the attached new candle label artwork.
2. Replace only the visible top printed label / artwork on the tea lid on the right with the attached new lid label artwork.

IMPORTANT:
Do NOT replace the entire tea lid.
Do NOT change the lid material, shape, size, rim, gloss, reflections, or perspective.
Only replace the printed artwork visible on the top surface of the lid.

STRICT PRESERVATION RULES:
- Keep the exact same box.
- Keep the exact same kraft cardboard texture.
- Keep the exact same straw / wood wool filling.
- Keep the exact same camera angle: top-down packshot.
- Keep the exact same crop and framing.
- Keep the exact same object positions and spacing.
- Keep the exact same candle jar shape, amber glass, and black lid.
- Keep the exact same tea container and lid geometry.
- Keep the exact same lighting, shadows, reflections, and highlights.
- Do not redesign the packaging.
- Do not add or remove objects.
- Do not stylize.
- Do not create a new composition.
- Do not move the products.

REALISM RULES:
- The candle label must look naturally printed and physically applied to the candle jar.
- Respect label perspective, curvature, slight glass reflections, and natural shadow integration.
- The lid label must look naturally printed or applied on the top surface of the existing black lid.
- Respect circular perspective, lid curvature, gloss, highlight falloff, and edge visibility.
- Preserve the original black rim around the lid.
- The final image must look like a real premium e-commerce product photo, not CGI.

GOLD FRAME PRESERVATION RULE:
The candle label contains a visible gold border frame around the label.
This gold frame must remain EXACTLY the same as in the original image.

STRICT RULES:
- Do not change the gold border.
- Do not recolor the gold border.
- Do not modify its thickness.
- Do not modify its shape.
- Do not remove it.
- Do not add additional decorative borders.

EDIT AREA LIMITATION:
Only edit the inner printed content inside the gold frame.
The gold frame must stay perfectly intact and identical to the original image.
The new label artwork must appear naturally inside the existing gold frame while preserving the frame exactly as it is.

ABSOLUTE LOCK:
This is an image editing task, not a redesign task.
Only swap the visible printed label on the candle and the visible printed artwork on the top of the tea lid.
Everything else must remain identical to the source image.

TEXT AND TYPOGRAPHY LOCK:
All text visible on the provided label artworks must be reproduced EXACTLY as in the reference images.

STRICT TEXT RULES:
- Do not change any words.
- Do not change spelling.
- Do not translate text.
- Do not paraphrase text.
- Do not shorten text.
- Do not add any new words.
- Do not remove any words.

TYPOGRAPHY RULES:
- Preserve the exact typography from the label artwork.
- Preserve font style, font weight, and letter spacing.
- Preserve capitalization and line breaks.
- Preserve logo placement and brand marks.
- Do not add decorative elements, flourishes, ornaments, or swirls.
- Do not invent new graphic elements.

The label designs must be transferred EXACTLY as provided on the reference label images.
The output must match the text and typography of the labels perfectly.`;

const requestBody = {
  contents: [{
    parts: [
      { inline_data: { mime_type: getMimeType(baseImageUrl), data: baseB64 } },
      { inline_data: { mime_type: getMimeType(labelImageUrl), data: labelB64 } },
      { inline_data: { mime_type: getMimeType(lidImageUrl), data: lidB64 } },
      { text: prompt },
    ],
  }],
  generationConfig: {
    responseModalities: ['IMAGE', 'TEXT'],
  },
};

const geminiRes = await fetch(
  `https://generativelanguage.googleapis.com/v1beta/models/gemini-3.1-flash-image-preview:generateContent?key=${GEMINI_API_KEY}`,
  {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(requestBody),
  }
);

if (!geminiRes.ok) {
  const errText = await geminiRes.text();
  throw new Error(`Gemini API error ${geminiRes.status}: ${errText}`);
}

const result = await geminiRes.json();
const imagePart = result.candidates?.[0]?.content?.parts?.find(p => p.inline_data);

if (!imagePart) {
  throw new Error('Gemini nie zwrocil obrazu. Response: ' + JSON.stringify(result).substring(0, 500));
}

return [{
  json: {
    product_name: productName,
    airtable_id: airtableId,
    image_base64: imagePart.inline_data.data,
    mime_type: imagePart.inline_data.mime_type || 'image/jpeg',
  },
}];

const item = $input.first();

const base64Data = item.json.image_base64;
const mimeType = item.json.mime_type || 'image/jpeg';
const ext = mimeType.includes('png') ? 'png' : 'jpg';
const fileName = `${item.json.product_name}.${ext}`;

const buffer = Buffer.from(base64Data, 'base64');
const binaryData = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);

return [{
  json: {
    product_name: item.json.product_name,
    airtable_id: item.json.airtable_id,
    fileName,
  },
  binary: {
    data: binaryData,
  },
}];
